sql:
SELECT SUM(beta) AS total_beta
FROM stock_performance_metrics
WHERE annual_return > 15;

SELECT ticker, pe_ratio
FROM stock_performance_metrics
WHERE beta > 1;

SELECT spm.ticker, AVG(spm.annual_return) AS average_return
FROM stock_performance_metrics spm
GROUP BY spm.ticker;

SELECT ticker
FROM stock_performance_metrics
WHERE pe_ratio > 30 AND beta < 1.5;

SELECT stocks.ticker, stocks.company_name, stocks.market_cap, stock_prices.open, stock_prices.close
FROM stocks
JOIN stock_prices ON stocks.ticker = stock_prices.ticker;

SELECT ticker, close
FROM stock_prices
WHERE date = '2022-01-01';

SELECT COUNT(DISTINCT user_id) AS unique_users, AVG(duration) AS avg_session_duration
FROM user_access_logs
WHERE ticker = '1';

SELECT d.ticker, AVG(d.dividend_amount) AS average_dividend
FROM dividends d
GROUP BY d.ticker;

SELECT AVG(sp.close - sp.open) AS average_price_movement
FROM stock_prices sp
WHERE sp.ticker = 'AAPL' AND strftime('%Y', sp.date) = '2022';

SELECT s.ticker, d.dividend_amount, d.ex_dividend_date, d.record_date
FROM stocks s
JOIN dividends d ON s.ticker = d.ticker;

SELECT ticker
FROM stock_performance_metrics
WHERE annual_return > 0 AND current_ratio > 1.0;

external_knowledge:
- Latest price refers to the closing price on the most recent date available in the stock_prices table;
- Dividend details refer to the most recent dividend amount and its corresponding record date;
- Stock split information refers to the most recent split ratio and its corresponding date.

